import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../../services/api';
import '../../styles/Clientes.css';

function ListaClientes() {
  const [clientes, setClientes] = useState([]);

  useEffect(() => {
    carregarClientes();
  }, []);

  const carregarClientes = async () => {
    try {
      const response = await api.listarClientes();
      setClientes(response.data);
    } catch (error) {
      alert('Erro ao carregar clientes: ' + error.message);
    }
  };

  const handleExcluir = async (id) => {
    if (window.confirm('Tem certeza que deseja excluir este cliente?')) {
      try {
        await api.deletarCliente(id);
        carregarClientes(); // Recarrega a lista após exclusão
      } catch (error) {
        alert('Erro ao excluir cliente: ' + error.message);
      }
    }
  };

  return (
    <div className="sysmtec-container">
      <header className="sysmtec-header">
        <h1>SYSMTEC</h1>
        <h2>TELA DE LISTAGEM DE CLIENTES</h2>
      </header>

      <div className="sysmtec-sidebar">
        <nav>
          <ul>
            <li><Link to="/agenda">Agenda</Link></li>
            <li className="active"><Link to="/clientes">Clientes</Link></li>
            <li><Link to="/projetos">Projetos e Serviços</Link></li>
            <li><Link to="/orcamentos">Orçamentos</Link></li>
            <li><Link to="/log">Log de alterações</Link></li>
          </ul>
        </nav>
      </div>

      <main className="sysmtec-main">
        <div className="clientes-header">
          <h3>+ ADICIONAR NOVO CLIENTE</h3>
          <Link to="/clientes/novo" className="add-button">+</Link>
        </div>

        <div className="clientes-list">
          {clientes.map(cliente => (
            <div key={cliente.id_cliente} className="cliente-card">
              <h4>{cliente.nome}</h4>
              <p>CPF/CNPJ: {cliente.cpf_cnpj_formatado}</p>
              <p>Celular: {cliente.celular_formatado}</p>
              <div className="cliente-actions">
                <Link to={`/clientes/editar/${cliente.id_cliente}`} className="edit-button">Editar</Link>
                <button onClick={() => handleExcluir(cliente.id_cliente)} className="delete-button">Excluir</button>
              </div>
            </div>
          ))}
        </div>
      </main>
    </div>
  );
}

export default ListaClientes;
